const item = $input.first();
const body = item.json.body || {};
const headers = item.json.headers || {};
const params = item.json.params || {};
let slug = params.slug || null;
if (!slug) slug = 'app-omega-laser';

let bearer = null;
const auth = headers.authorization || headers.Authorization || '';
if (auth && auth.toLowerCase().startsWith('bearer ')) {
  bearer = auth.slice(7).trim();
}

const mensagem = body.mensagem || {};
const origem = (mensagem.origem || '').toUpperCase();
const setor = (body.setor || '').toLowerCase();

let direction = 'unknown';
let respondent_type = 'unknown';
let respondent_name = null;
if (origem === 'CLIENTE') { direction = 'incoming'; respondent_type = 'unknown'; }
else if (origem === 'ATENDENTE') { direction = 'outgoing'; respondent_type = 'human'; respondent_name = mensagem.atendente_nome || null; }
else if (origem === 'SISTEMA') { direction = 'outgoing'; respondent_type = 'ai'; }

const tipo = (mensagem.tipo || 'texto').toLowerCase();
const conteudo = mensagem.conteudo || null;
const is_audio = tipo === 'audio';

const b64 = (s) => s ? Buffer.from(String(s)).toString('base64') : '__NULL__';

return [{
  json: {
    slug, bearer, setor, origem, direction, respondent_type, tipo,
    message_id: mensagem.id || null,
    remote_jid: mensagem.conversa_id || body.conversa_id || null,
    atendente_id: mensagem.atendente_id || null,
    atendente_nome: mensagem.atendente_nome || null,
    enviada_em: mensagem.enviada_em || null,
    status_msg: mensagem.status || 'recebida',
    // base64 encoded for safe transport via queryReplacement
    conteudo_b64: b64(is_audio ? null : conteudo),
    audio_url_b64: b64(is_audio ? conteudo : null),
    respondent_name_b64: b64(respondent_name),
    metadados_b64: Buffer.from(JSON.stringify(body)).toString('base64'),
    atendente_nome_b64: b64(mensagem.atendente_nome || null)
  }
}];

const payload = $('Normalizar Payload').first().json;
const rows = $input.all().map(i => i.json);
const projeto = rows.length > 0 && rows[0].projeto_id ? rows[0] : null;

if (!projeto) {
  return [{ json: { ...payload, _error: 'slug_not_found', _status: 404 } }];
}
if (!projeto.webhook_api_key || !payload.bearer || projeto.webhook_api_key !== payload.bearer) {
  return [{ json: { ...payload, _error: 'invalid_bearer', _status: 401 } }];
}
if (!payload.setor) {
  return [{ json: { ...payload, _error: 'setor_required', _status: 400 } }];
}
if (!payload.message_id) {
  return [{ json: { ...payload, _error: 'message_id_required', _status: 400 } }];
}
return [{ json: { ...payload, projeto_id: projeto.projeto_id, _error: null, _status: 200 } }];

const payload = $('Validar Auth').first().json;
const rows = $input.all().map(i => i.json);
const row = rows.length > 0 && rows[0].numero_id ? rows[0] : null;
if (!row) {
  return [{ json: { ...payload, _error: 'setor_not_registered', _status: 400 } }];
}
return [{ json: { ...payload, numero_id: row.numero_id, _error: null, _status: 200 } }];

const payload = $('Check Numero Existe').first().json;
const origem = payload.origem;
let agente_humano_id = null;
if (origem === 'ATENDENTE') {
  try {
    const r = $('Upsert Agente Humano').first().json;
    agente_humano_id = r.agente_humano_id || null;
  } catch (e) { agente_humano_id = null; }
}
return [{ json: { ...payload, agente_humano_id } }];

const ctx = $('Merge Agente').first().json;
const rows = $input.all().map(i => i.json);
const inserted = rows.length > 0 && rows[0].inserted_id ? rows[0].inserted_id : null;
return [{ json: { ...ctx, inserted_id: inserted, is_duplicate: !inserted } }];
